proof_block:
// Domain equalities — both post-states share the same proc/thread/endpoint/container
// domain as pre_self_, so they share the same domain as each other.  These are also
// the side conditions of all the per-element forall quantifiers below, so we want
// them in scope so that the foralls fire symmetrically on the two runs.
assert(post1_self_.proc_dom() == post2_self_.proc_dom());
assert(post1_self_.thread_dom() == post2_self_.thread_dom());
assert(post1_self_.endpoint_dom() == post2_self_.endpoint_dom());
assert(post1_self_.container_dom() == post2_self_.container_dom());

// Free-page count: both equal pre - 1, so equal to each other.
assert(post1_self_.get_num_of_free_pages() == post2_self_.get_num_of_free_pages());

// Pull both forall|p_ptr| ensures into a single forall that compares the two runs
// directly.  z3 picks `post1_self_.get_proc(p_ptr)` for run1's ensures and
// `post2_self_.get_proc(p_ptr)` for run2's ensures (auto-trigger); by asserting
// the joint forall we force both to fire on the same `p_ptr`, after which they
// chain through the common `pre_self_.get_proc(p_ptr)`.
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
    post1_self_.proc_dom().contains(p_ptr)
    implies post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {
}

assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_address_space(p_ptr), post2_self_.get_address_space(p_ptr)]
    post1_self_.proc_dom().contains(p_ptr)
    implies post1_self_.get_address_space(p_ptr) =~= post2_self_.get_address_space(p_ptr) by {
}

assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_io_space(p_ptr), post2_self_.get_io_space(p_ptr)]
    post1_self_.proc_dom().contains(p_ptr)
    && post1_self_.get_proc_has_iommu_table(p_ptr)
    && post2_self_.get_proc_has_iommu_table(p_ptr)
    && p_ptr != target_proc_ptr
    implies post1_self_.get_io_space(p_ptr) =~= post2_self_.get_io_space(p_ptr) by {
}

assert forall|t_ptr: ThreadPtr|
    #![trigger post1_self_.get_thread(t_ptr), post2_self_.get_thread(t_ptr)]
    post1_self_.thread_dom().contains(t_ptr)
    implies post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
}

assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
    post1_self_.endpoint_dom().contains(e_ptr)
    implies post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr) by {
}

assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr), post2_self_.get_container(c_ptr)]
    post1_self_.container_dom().contains(c_ptr)
    && c_ptr != post1_self_.get_proc(target_proc_ptr).owning_container
    && c_ptr != post2_self_.get_proc(target_proc_ptr).owning_container
    implies post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr)
        && post1_self_.get_container_owned_pages(c_ptr) =~= post2_self_.get_container_owned_pages(c_ptr) by {
}

assert forall|p: Pcid|
    #![trigger post1_self_.mem_man.pcid_to_proc_ptr(p), post2_self_.mem_man.pcid_to_proc_ptr(p)]
    post1_self_.mem_man.pcid_active(p) && post2_self_.mem_man.pcid_active(p)
    implies post1_self_.mem_man.pcid_to_proc_ptr(p) == post2_self_.mem_man.pcid_to_proc_ptr(p) by {
}

assert forall|i: IOid|
    #![trigger post1_self_.mem_man.ioid_to_proc_ptr(i), post2_self_.mem_man.ioid_to_proc_ptr(i)]
    post1_self_.mem_man.ioid_active(i) && post2_self_.mem_man.ioid_active(i)
    implies post1_self_.mem_man.ioid_to_proc_ptr(i) == post2_self_.mem_man.ioid_to_proc_ptr(i) by {
}

// Re-state the io_space ensures at target_proc_ptr in normalised form.  Both
// runs produce `pre_self_.get_io_space(target_proc_ptr).insert(target_va, r_i)`.
assert(post1_self_.get_io_space(target_proc_ptr)
    =~= pre_self_.get_io_space(target_proc_ptr).insert(target_va, r1));
assert(post2_self_.get_io_space(target_proc_ptr)
    =~= pre_self_.get_io_space(target_proc_ptr).insert(target_va, r2));

// Container at the affected slot: every named field is constrained to be the
// pre-value for both runs, so they agree pairwise.  Re-asserting them gives
// z3 the per-field equality bridges without needing a forall.
let oc = pre_self_.get_proc(target_proc_ptr).owning_container;
assert(post1_self_.get_container(oc).owned_procs =~= pre_self_.get_container(oc).owned_procs);
assert(post2_self_.get_container(oc).owned_procs =~= pre_self_.get_container(oc).owned_procs);
assert(post1_self_.get_container(oc).owned_procs =~= post2_self_.get_container(oc).owned_procs);

assert(post1_self_.get_container(oc).parent =~= pre_self_.get_container(oc).parent);
assert(post2_self_.get_container(oc).parent =~= pre_self_.get_container(oc).parent);

assert(post1_self_.get_container(oc).parent_rev_ptr =~= pre_self_.get_container(oc).parent_rev_ptr);
assert(post2_self_.get_container(oc).parent_rev_ptr =~= pre_self_.get_container(oc).parent_rev_ptr);

assert(post1_self_.get_container(oc).children =~= pre_self_.get_container(oc).children);
assert(post2_self_.get_container(oc).children =~= pre_self_.get_container(oc).children);

assert(post1_self_.get_container(oc).owned_endpoints =~= pre_self_.get_container(oc).owned_endpoints);
assert(post2_self_.get_container(oc).owned_endpoints =~= pre_self_.get_container(oc).owned_endpoints);

assert(post1_self_.get_container(oc).owned_threads =~= pre_self_.get_container(oc).owned_threads);
assert(post2_self_.get_container(oc).owned_threads =~= pre_self_.get_container(oc).owned_threads);

assert(post1_self_.get_container(oc).owned_cpus =~= pre_self_.get_container(oc).owned_cpus);
assert(post2_self_.get_container(oc).owned_cpus =~= pre_self_.get_container(oc).owned_cpus);

assert(post1_self_.get_container(oc).scheduler =~= pre_self_.get_container(oc).scheduler);
assert(post2_self_.get_container(oc).scheduler =~= pre_self_.get_container(oc).scheduler);

assert(post1_self_.get_container(oc).subtree_set =~= pre_self_.get_container(oc).subtree_set);
assert(post2_self_.get_container(oc).subtree_set =~= pre_self_.get_container(oc).subtree_set);

assert(post1_self_.get_container(oc).depth =~= pre_self_.get_container(oc).depth);
assert(post2_self_.get_container(oc).depth =~= pre_self_.get_container(oc).depth);

// quota subtract-by-1 is functional, so post1's quota and post2's quota are the
// same function of pre's quota.
assert(pre_self_.get_container(oc).quota.spec_subtract_mem_4k(
    post1_self_.get_container(oc).quota, 1));
assert(pre_self_.get_container(oc).quota.spec_subtract_mem_4k(
    post2_self_.get_container(oc).quota, 1));
